// Kandidaten sammeln: Kunden, die vor WINBACK_TAGE Tagen gekauft haben
const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at && o.email && o.customer);
const kandidaten = {};
for (const o of orders) {
  if (!kandidaten[o.email]) {
    kandidaten[o.email] = {
      customer_id: o.customer.id,
      email: o.email,
      vorname: o.customer.first_name || '',
      artikel: (o.line_items || []).map(li => li.title).slice(0, 3).join(', '),
      alte_order_id: o.id
    };
  }
}
return Object.values(kandidaten).map(k => ({ json: k }));

// Nur Kunden behalten, die seitdem NICHT mehr gekauft haben + Dedup
const sd = $getWorkflowStaticData('global');
sd.winback = sd.winback || [];
const setup = $('⚙️ Setup').first().json;
const kandidat = $('🧠 Kandidaten sammeln').item.json;
const neuereBestellungen = ($json.orders || []).filter(o => !o.cancelled_at);

if (neuereBestellungen.length > 0) return null; // hat wieder gekauft -> kein Winback
if (sd.winback.includes(kandidat.email)) return null; // schon angeschrieben
sd.winback.push(kandidat.email);
if (sd.winback.length > 2000) sd.winback = sd.winback.slice(-2000);

const prompt = 'Du bist E-Mail-Marketing-Profi fuer den Onlineshop "' + setup.SHOP_NAME + '".\n' +
  'Dieser Kunde hat vor ' + setup.WINBACK_TAGE + ' Tagen gekauft und seitdem nichts mehr bestellt. Schreibe eine Winback-E-Mail auf Deutsch (Du-Form), maximal 130 Woerter.\n\n' +
  'Daten:\n- Vorname: ' + (kandidat.vorname || 'unbekannt (neutral anreden)') + '\n- Damals gekauft: ' + kandidat.artikel + '\n- Shop-Link: ' + setup.SHOP_URL + '\n- Rabattcode: ' + setup.WINBACK_RABATT_CODE + ' (' + setup.WINBACK_RABATT_PROZENT + '%)\n\n' +
  'Anforderungen: "Wir vermissen dich"-Vibe ohne cringe zu sein, beziehe dich auf den damaligen Kauf, Rabattcode als Dankeschoen praesentieren, EIN klarer Button (als <a> mit Inline-Button-Styling) zum Shop, leichte Dringlichkeit (Code 7 Tage gueltig). Mobiltaugliches HTML mit Inline-CSS.\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "<komplettes E-Mail-HTML>"}';

return { json: { email: kandidat.email, vorname: kandidat.vorname, prompt } };

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Wir vermissen dich! 💛', html: text };
}
const orig = $('🧹 Inaktive filtern & Prompt').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;
return { json: {
  empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + daten.betreff,
  email_html: daten.html
}};
